package com.pos;
import javax.swing.*; import java.awt.*; import java.sql.*;
public class UserMessagePanel extends JPanel {private final UserSession s;private final QueryTableModel m=new QueryTableModel();private final JTable t=new JTable(m);private final JTextField subject=new JTextField(18),body=new JTextField(35);public UserMessagePanel(UserSession s){super(new BorderLayout(8,8));this.s=s;add(UIUtils.title("Support Messages"),BorderLayout.NORTH);add(new JScrollPane(t),BorderLayout.CENTER);JPanel f=new JPanel();f.add(new JLabel("Subject"));f.add(subject);f.add(new JLabel("Message"));f.add(body);JButton send=new JButton("Send"),refresh=new JButton("Refresh");f.add(send);f.add(refresh);add(f,BorderLayout.SOUTH);send.addActionListener(e->send());refresh.addActionListener(e->load());load();}
 private void load(){try{m.load("SELECT message_id,subject,body,reply_text,status,created_at FROM messages WHERE sender_id=? ORDER BY message_id DESC",s.userId);}catch(Exception e){UIUtils.error(this,e);}}
 private void send(){try(Connection c=DB.getConnection();PreparedStatement p=c.prepareStatement("INSERT INTO messages(sender_id,subject,body,status) VALUES(?,?,?,'OPEN')")){p.setInt(1,s.userId);p.setString(2,subject.getText());p.setString(3,body.getText());p.executeUpdate();Audit.log(s,"SEND_MESSAGE",subject.getText());load();}catch(Exception e){UIUtils.error(this,e);}}
}
